from collections import deque

class Solution:
    def countOperationsToEmptyArray(self, nums):
        dq = deque(nums)
        ops = 0
        while dq:
            if dq[0] == min(dq):
                dq.popleft()
            else:
                dq.append(dq.popleft())
            ops += 1
        return ops

