class Solution:
    def countOperationsToEmptyArray(self, nums):
        n = len(nums)
        order = sorted(range(n), key=lambda i: nums[i])
        tree = [0] * (n + 1)

        def update(i, delta):
            while i <= n:
                tree[i] += delta
                i += i & (-i)

        def prefix(i):
            s = 0
            while i > 0:
                s += tree[i]
                i -= i & (-i)
            return s

        for i in range(1, n + 1):
            update(i, 1)

        ops = 0
        p = 1
        for orig in order:
            pos = orig + 1
            if pos >= p:
                count_between = prefix(pos - 1) - prefix(p - 1)
            else:
                count_between = (prefix(n) - prefix(p - 1)) + prefix(pos - 1)
            ops += count_between + 1
            update(pos, -1)
            p = pos + 1
            if p > n:
                p = 1
        return ops

