var countOperationsToEmptyArray = function(nums) {
    const n = nums.length;
    const order = Array.from({ length: n }, (_, i) => i);
    order.sort((a, b) => nums[a] - nums[b]);
    const tree = new Array(n + 1).fill(0);

    function update(i, delta) {
        for (; i <= n; i += i & (-i)) tree[i] += delta;
    }

    function prefix(i) {
        let s = 0;
        for (; i > 0; i -= i & (-i)) s += tree[i];
        return s;
    }

    for (let i = 1; i <= n; i++) update(i, 1);

    let ops = 0;
    let p = 1;
    for (const orig of order) {
        const pos = orig + 1;
        let countBetween;
        if (pos >= p) {
            countBetween = prefix(pos - 1) - prefix(p - 1);
        } else {
            countBetween = (prefix(n) - prefix(p - 1)) + prefix(pos - 1);
        }
        ops += countBetween + 1;
        update(pos, -1);
        p = pos + 1;
        if (p > n) p = 1;
    }
    return ops;
};
